<script setup lang="ts">
import { ref } from 'vue'; import PageHeader from '../components/PageHeader.vue'; import PathField from '../components/PathField.vue'
const input=ref(''); const output=ref(''); const model=ref('YOLOX-Tiny'); const provider=ref('cpu'); const threshold=ref(.35); const loading=ref(false)
const models=['YOLOX-Tiny','YOLOX-S','YOLOX-L','NanoDet-Plus-m-320','NanoDet-Plus-m-416','NanoDet-Plus-m-1.5x-416']
async function run(){ loading.value=true; await window.mel.jobs.create({kind:'detection',title:`Detect with ${model.value}`,config:{input_path:input.value,output_path:output.value,model:model.value,execution_provider:provider.value,score_threshold:threshold.value}}); loading.value=false }
</script>
<template><div class="page-wrap"><PageHeader eyebrow="Detection Studio" title="Multi-model inference with durable checkpoints" subtitle="Choose representative YOLOX and NanoDet tiers, preserve item-level progress and compare disagreement without mislabeling it as accuracy." icon="mdi-vector-square" color="accent"/><v-card class="glass pa-6"><PathField v-model="input" label="Image corpus"/><PathField v-model="output" label="Detection output directory"/><v-row><v-col cols="12" md="4"><v-select v-model="model" label="Model" :items="models" prepend-inner-icon="mdi-cube-outline"/></v-col><v-col cols="12" md="4"><v-select v-model="provider" label="Execution provider" :items="['cpu','directml','cuda','coreml']" prepend-inner-icon="mdi-expansion-card-variant"/></v-col><v-col cols="12" md="4"><v-slider v-model="threshold" label="Score threshold" min="0.05" max="0.95" step="0.05" thumb-label color="accent"/></v-col></v-row><v-btn color="accent" prepend-icon="mdi-crosshairs-gps" :loading="loading" :disabled="!input||!output" @click="run">Start detection</v-btn></v-card></div></template>
